#include <stdio.h>
#include <stdlib.h>
int main() {
    int n;
    scanf("%d", &n);
    int* planks = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &planks[i]);
    }
    int min = planks[0];
    for (int i = 1; i < n; i++) {
        if (planks[i] < min) {
            min = planks[i];
        }
    }
    int total = 0;
    for (int i = 0; i < n; i++) {
        total += planks[i];
    }
    int result = (total + min - 1) / min - n;
    printf("%d\n", result);
    free(planks);
    return 0;
}

