        int n = scanner.nextInt();
        int[] planks = new int[n];
        for (int i = 0; i < n; i++) {
            planks[i] = scanner.nextInt();
        }
        int min = planks[0];
        for (int i = 1; i < n; i++) {
            if (planks[i] < min) {
                min = planks[i];
            }
        }
        int total = 0;
        for (int i = 0; i < n; i++) {
            total += planks[i];
        }
        int result = (total + min - 1) / min - n;
        System.out.println(result);
    }
}

code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let planks;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        planks = input.split(' ').map(Number);
        const minPlank = Math.min(...planks);
        const totalLength = planks.reduce((a, b) => a + b, 0);
        const result = Math.ceil(totalLength / minPlank) - n;
        console.log(result);
        rl.close();
    }
});
